pure fn sum_range(lo: Number, hi: Number) -> Number {
    total = 0
    for i in range(lo, hi + 1) { total = total + i }
    return total
}
entry main(x: Text) { return sum_range(1, 100) }

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}
entry main(x: Text) { return factorial(6) }

pure fn sum_even(lo: Number, hi: Number) -> Number {
    total = 0
    for i in range(lo, hi + 1) {
        if i % 2 == 0 { total = total + i }
    }
    return total
}
entry main(x: Text) { return sum_even(2, 20) }

pure fn average(nums: Number) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
entry main(x: Text) { return average([10, 20, 30, 40, 50]) }

pure fn is_vowel(c: Text) -> Boolean {
    return c in ["a", "e", "i", "o", "u"]
}
pure fn count_vowels(s: Text) -> Number {
    total = 0
    for c in split(lower(s), "") {
        if is_vowel(c) { total = total + 1 }
    }
    return total
}
entry main(x: Text) { return count_vowels("Hello World") }

pure fn count_letter(s: Text, c: Text) -> Number {
    total = 0
    for ch in split(lower(s), "") {
        if ch == c { total = total + 1 }
    }
    return total
}
entry main(x: Text) { return count_letter("banana", "a") }

pure fn word_count(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(x: Text) { return word_count("the quick brown fox jumps") }

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    result = ""
    for i in range(0, length(chars)) {
        result = join([result, get(chars, length(chars) - 1 - i)], "")
    }
    return result
}
entry main(x: Text) { return reverse_text("racecar") }

pure fn fib(n: Number) -> Number {
    if n <= 1 { return n }
    return fib(n - 1) + fib(n - 2)
}
entry main(x: Text) { return fib(10) }

pure fn max_of(nums: Number) -> Number {
    best = get(nums, 0)
    for n in nums {
        if n > best { best = n }
    }
    return best
}
entry main(x: Text) { return max_of([17, 42, 8, 23, 39]) }

pure fn min_of(nums: Number) -> Number {
    best = get(nums, 0)
    for n in nums {
        if n < best { best = n }
    }
    return best
}
entry main(x: Text) { return min_of([17, 42, 8, 23, 39]) }

