intent assess_scores(summary: Text) -> Text {
    goal: a one-sentence verbal assessment
}
pure fn average(nums: Number) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
entry main(x: Text) {
    scores = [85, 92, 78, 95, 88]
    avg = average(scores)
    summary = join(["average is ", to_text(avg)], "")
    return join([summary, " - ", assess_scores(summary)], "")
}

intent judge_density(summary: Text) -> Text {
    goal: high or low
}
pure fn count_vowels(s: Text) -> Number {
    total = 0
    for c in split(lower(s), "") {
        if c in ["a","e","i","o","u"] { total = total + 1 }
    }
    return total
}
entry main(x: Text) {
    word = "Mississippi"
    n = count_vowels(word)
    summary = join([to_text(n), " vowels in ", to_text(length(word)), " letters"], "")
    return join([summary, " - density is ", judge_density(summary)], "")
}

