intent rate_commonness(word: Text) -> Text {
    goal: common or uncommon
}
pure fn longest(words: Text) -> Text {
    best = get(words, 0)
    for w in words {
        if length(w) > length(best) { best = w }
    }
    return best
}
entry main(x: Text) {
    w = longest(["cat", "elephant", "dog"])
    return join([w, " is ", rate_commonness(w)], "")
}

